const skus = items.map(i => i.json);
const month = new Date().toLocaleString('default', { month: 'long' });

return [{
  json: {
    prompt: `You are a D2C demand forecasting expert. Based on the last 90 days of sales data, predict demand for the next 30 days for each SKU.

Current month: ${month}

Consider:
- Seasonal trends for this month
- Sales velocity from last 90 days
- Product category demand patterns
- Festival/holiday seasons if applicable

Respond ONLY in this JSON format:
{
  "forecast_month": "string",
  "forecasts": [
    {
      "sku_id": "string",
      "product_name": "string",
      "category": "string",
      "predicted_units_30d": number,
      "current_stock": number,
      "stock_needed": number,
      "action": "reorder now | stock up | sufficient | reduce",
      "seasonality_note": "string",
      "confidence": "high | medium | low"
    }
  ]
}

Rules:
- stock_needed = predicted_units_30d - current_stock (if negative set to 0)
- If stock_needed > 0: action = reorder now or stock up
- If current_stock > predicted_units_30d * 2: action = reduce
- Otherwise: action = sufficient
- Add seasonality_note based on month and category

Sales Data:
${JSON.stringify(skus, null, 2)}`
  }
}];

const forecasts = items;
const month = forecasts[0]?.json.forecast_month || 'This Month';

let email = `D2C Demand Forecast Report — ${month}\n`;
email += `Generated: ${new Date().toDateString()}\n`;
email += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n`;

const reorder = forecasts.filter(f => f.json.action === 'reorder now');
const stockUp = forecasts.filter(f => f.json.action === 'stock up');
const reduce = forecasts.filter(f => f.json.action === 'reduce');

if (reorder.length > 0) {
  email += `🚨 REORDER NOW\n\n`;
  reorder.forEach(f => {
    email += `Product: ${f.json.product_name}\n`;
    email += `Predicted Demand (30d): ${f.json.predicted_units_30d} units\n`;
    email += `Current Stock: ${f.json.current_stock} units\n`;
    email += `Units to Order: ${f.json.stock_needed} units\n`;
    email += `Note: ${f.json.seasonality_note}\n`;
    email += `Confidence: ${f.json.confidence}\n\n`;
  });
}

if (stockUp.length > 0) {
  email += `📦 STOCK UP SOON\n\n`;
  stockUp.forEach(f => {
    email += `Product: ${f.json.product_name}\n`;
    email += `Predicted Demand (30d): ${f.json.predicted_units_30d} units\n`;
    email += `Units to Order: ${f.json.stock_needed} units\n`;
    email += `Note: ${f.json.seasonality_note}\n\n`;
  });
}

if (reduce.length > 0) {
  email += `⬇️ CONSIDER REDUCING\n\n`;
  reduce.forEach(f => {
    email += `Product: ${f.json.product_name} — overstock likely next 30 days\n`;
  });
}

email += `\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
email += `Total SKUs needing action: ${forecasts.length}`;

return [{ json: { email_body: email, total_action: forecasts.length, month } }];

const products = items[0].json.products;

return products.map(p => {
  const unitsSold = Math.floor(Math.random() * 15) + 1;
  const remaining = p.stock - unitsSold;
  return {
    json: {
      sku_id: p.id,
      product_name: p.title,
      category: p.category,
      current_stock: p.stock,
      units_sold: unitsSold,
      remaining_stock: remaining < 0 ? 0 : remaining,
      supplier_email: "user@example.com",
      reorder_point: 20,
      lead_time_days: 7,
      status: "active",
      date: new Date().toISOString().split('T')[0]
    }
  };
});

const inventory = $('Read Inventory Master').all();
const salesLog = $('Read Sales Log').all();

const today = new Date();
const sevenDaysAgo = new Date(today - 7 * 24 * 60 * 60 * 1000);

return inventory.map(item => {
  const sku = item.json.sku_id;

  const recentSales = salesLog.filter(s => {
    const saleDate = new Date(s.json.date);
    return s.json.sku_id == sku && saleDate >= sevenDaysAgo;
  });

  const totalSold = recentSales.reduce((sum, s) => sum + Number(s.json.units_sold), 0);
  const avgDailySales = totalSold / 7;
  const currentStock = Number(item.json.current_stock);
  const daysRemaining = avgDailySales > 0 ? Math.floor(currentStock / avgDailySales) : 999;

  let flag = '🟢 Healthy';
  if (daysRemaining < 14) flag = '🔴 Stockout Risk';
  else if (totalSold === 0) flag = '🟡 Dead Stock';
  else if (daysRemaining > 60) flag = '🟡 Overstock';

  return {
    json: {
      sku_id: sku,
      product_name: item.json.product_name,
      category: item.json.category,
      current_stock: currentStock,
      avg_daily_sales: avgDailySales.toFixed(2),
      days_remaining: daysRemaining,
      flag,
      supplier_email: item.json.supplier_email,
      date: new Date().toISOString().split('T')[0]
    }
  };
});

