return items.map(item => {
  const avgDailySales = Number(item.json.avg_daily_sales);
  const leadTimeDays = Number(item.json.lead_time_days) || 7;
  const currentStock = Number(item.json.current_stock);

  // Skip if avg_daily_sales is 0 (SW2 hasn't populated it yet)
  if (avgDailySales === 0) {
    return {
      json: {
        ...item.json,
        skipped: true,
        skip_reason: "avg_daily_sales is 0 — SW2 may not have run yet"
      }
    };
  }

  const bufferStock = Math.ceil(avgDailySales * 7);
  const reorderQty = Math.ceil((avgDailySales * leadTimeDays) + bufferStock - currentStock);
  const poNumber = `PO-${item.json.sku_id}-${Date.now()}`;

  return {
    json: {
      ...item.json,
      skipped: false,
      reorder_qty: reorderQty > 0 ? reorderQty : 10,
      buffer_stock: bufferStock,
      po_number: poNumber,
      po_date: new Date().toISOString().split('T')[0]
    }
  };
});

