return [{
  json: {
    prompt: `You are a D2C inventory strategist. Analyze the following slow-moving or dead stock SKUs and recommend actions.

For each SKU respond ONLY in this JSON format:
{
  "recommendations": [
    {
      "sku_id": "string",
      "product_name": "string",
      "flag": "string",
      "action": "bundle | discount | kill | monitor",
      "discount_percent": number or null,
      "reason": "string",
      "urgency": "high | medium | low"
    }
  ]
}

SKU Data:
${JSON.stringify(skus, null, 2)}

Rules:
- If stock > 100 and daily sales < 1: recommend kill or heavy discount (30-50%)
- If stock 50-100 and daily sales < 2: recommend bundle or moderate discount (15-25%)
- If days_remaining > 60: recommend monitor or light discount (10-15%)
- Always give a clear reason`
  }
}];

const response = items[0].json.output[0].content[0].text;
const cleaned = response.replace(/```json|```/g, '').trim();
const parsed = JSON.parse(cleaned);

return parsed.recommendations.map(rec => ({
  json: rec
}));

const recs = items;

let emailBody = `D2C Supply Chain — Weekly Dead Inventory Report\n`;
emailBody += `Generated: ${new Date().toDateString()}\n`;
emailBody += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n`;

const high = recs.filter(r => r.json.urgency === 'high');
const medium = recs.filter(r => r.json.urgency === 'medium');
const low = recs.filter(r => r.json.urgency === 'low');

if (high.length > 0) {
  emailBody += `🔴 HIGH URGENCY (Act This Week)\n\n`;
  high.forEach(r => {
    emailBody += `Product: ${r.json.product_name}\n`;
    emailBody += `Action: ${r.json.action.toUpperCase()}`;
    if (r.json.discount_percent) emailBody += ` — ${r.json.discount_percent}% off`;
    emailBody += `\nReason: ${r.json.reason}\n\n`;
  });
}

if (medium.length > 0) {
  emailBody += `🟡 MEDIUM URGENCY (Act This Month)\n\n`;
  medium.forEach(r => {
    emailBody += `Product: ${r.json.product_name}\n`;
    emailBody += `Action: ${r.json.action.toUpperCase()}`;
    if (r.json.discount_percent) emailBody += ` — ${r.json.discount_percent}% off`;
    emailBody += `\nReason: ${r.json.reason}\n\n`;
  });
}

if (low.length > 0) {
  emailBody += `🟢 LOW URGENCY (Monitor)\n\n`;
  low.forEach(r => {
    emailBody += `Product: ${r.json.product_name} — ${r.json.action.toUpperCase()}\n`;
  });
}

emailBody += `\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
emailBody += `Total SKUs flagged: ${recs.length}`;

return [{ json: { email_body: emailBody, total_flagged: recs.length } }];

const salesLog = $('Read sales log').all();
const inventory = $('Read Inventory Master3').all();

const today = new Date();
const ninetyDaysAgo = new Date(today - 90 * 24 * 60 * 60 * 1000);

// Group sales by SKU
const skuSales = {};
salesLog.forEach(s => {
  const saleDate = new Date(s.json.date);
  if (saleDate >= ninetyDaysAgo) {
    const sku = String(s.json.sku_id);
    if (!skuSales[sku]) skuSales[sku] = { total_sold: 0, days_count: 0 };
    skuSales[sku].total_sold += Number(s.json.units_sold);
    skuSales[sku].days_count += 1;
  }
});

// Merge with inventory
const result = inventory.map(item => {
  const sku = String(item.json.sku_id);
  const sales = skuSales[sku] || { total_sold: 0, days_count: 0 };
  const avgDaily = sales.days_count > 0 ? (sales.total_sold / sales.days_count).toFixed(2) : 0;

  return {
    json: {
      sku_id: sku,
      product_name: item.json.product_name,
      category: item.json.category,
      current_stock: item.json.current_stock,
      total_sold_90d: sales.total_sold,
      avg_daily_sales_90d: avgDaily,
      lead_time_days: item.json.lead_time_days || 7
    }
  };
});

return result;

